import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: URL {
        switch self {
        case .development:
            return URL(string: "https://api.example.com/dev")!
        case .staging:
            return URL(string: "https://api.example.com/stage")!
        case .production:
            return URL(string: "https://api.example.com/prod")!
        }
    }
}

enum APIError: Error {
    case invalidResponse
    case networkError
    case parsingError
}

class NetworkManager {
    private let environment: Environment
    
    init(environment: Environment) {
        self.environment = environment
    }
    
    func fetchData(completion: @escaping (Result<Data, APIError>) -> Void) {
        var urlRequest = URLRequest(url: environment.baseURL.appendingPathComponent("data"))
        urlRequest.httpMethod = "GET"
        
        let task = URLSession.shared.dataTask(with: urlRequest) { data, response, error in
            if let error = error {
                completion(.failure(.networkError))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
                completion(.failure(.invalidResponse))
                return
            }
            
            guard let data = data else {
                completion(.failure(.parsingError))
                return
            }
            
            completion(.success(data))
        }
        
        task.resume()
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Result<Void, APIError>) -> Void) {
        var urlRequest = URLRequest(url: environment.baseURL.appendingPathComponent("auth"))
        urlRequest.httpMethod = "POST"
        urlRequest.httpBody = try? JSONEncoder().encode(["username": username, "password": password])
        urlRequest.addValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let task = URLSession.shared.dataTask(with: urlRequest) { data, response, error in
            if let error = error {
                completion(.failure(.networkError))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
                completion(.failure(.invalidResponse))
                return
            }
            
            completion(.success(()))
        }
        
        task.resume()
    }
}